                        <a href={result.imageUrl || '#'} download={`ai-product-${result.id}.png`} className="p-2 bg-white rounded-full text-gray-800 hover:bg-gray-100 shadow-lg transform hover:scale-110 transition-transform pointer-events-auto"><Download className="w-5 h-5" /></a>
                      </div>
                    )}
                  </div>

                  <div className="p-4 flex-1 flex flex-col">
                    <div className="flex justify-between items-start mb-2"><h4 className="font-semibold text-gray-900 text-sm truncate pr-2" title={result.name}>{result.name}</h4>{result.status === 'completed' && <span className="text-[10px] text-green-600 bg-green-50 px-1.5 py-0.5 rounded border border-green-100 font-medium flex items-center flex-shrink-0"><Check className="w-3 h-3 mr-1" /> OK</span>}</div>
                    <div className="mt-auto relative group/prompt">
                      <p className="text-[10px] text-gray-400 line-clamp-2 leading-relaxed cursor-help">Prompt: {result.finalPrompt}</p>
                      <button onClick={() => copyPrompt(result.finalPrompt, result.id)} className="absolute right-0 bottom-0 p-1 bg-white border border-gray-200 rounded text-gray-400 hover:text-indigo-600 opacity-0 group-hover/prompt:opacity-100 transition-opacity">{copiedId === result.id ? <Check className="w-3 h-3 text-green-500" /> : <Copy className="w-3 h-3" />}</button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

