  { id: 7, name: '斜俯拍', type: 'High Oblique', promptSuffix: 'high-angle oblique view, camera positioned 45 degrees above the subject looking down, showing depth and dimension, clear overview, professional studio lighting, 8k resolution', description_cn: '45度俯瞰视角，展示产品的深度与全貌。' },
  { id: 8, name: '艺术静物 (几何展台)', type: 'Geo Still Life', promptSuffix: 'creative still life photography, conceptual product photography, product styled on geometric stone podiums and blocks, architectural composition, sculptural styling, soft artistic studio lighting, high-end minimalist aesthetic, neutral tones, 8k resolution', description_cn: '在几何展台上进行艺术造型，雕塑感构图。' },
  { id: 9, name: '面料垂感展示', type: 'Fabric Drape', promptSuffix: "Duvet cover fabric hanging on a minimalist display rack, naturally draped with soft, elegant wavy folds to showcase the material's excellent drape and wrinkle-resistant texture, professional soft studio lighting, highly detailed fabric, 8k commercial photography, masterpiece", description_cn: '将被套面料悬挂展示，以自然垂落的波浪形态，突出面料的垂坠感与抗皱性。' },
];

export const dynamicAngleSlots: Angle[] = [
  { id: 10, name: 'AI 智能视点 A', type: 'Smart Analysis', promptSuffix: 'analyzing...', description_cn: 'AI 正在探索独特视角...', isDynamic: true },
  { id: 11, name: 'AI 智能视点 B', type: 'Smart Analysis', promptSuffix: 'analyzing...', description_cn: 'AI 正在探索独特视角...', isDynamic: true },
];

import React, { useState, useRef, useEffect } from 'react';
import {
  Upload, ImageIcon, Camera, Download, Maximize2, RefreshCw, Sparkles,
  Layers, Eye, Wand2, Copy, Check, AlertCircle, X, Trash2,
  Shuffle, BrainCircuit, Edit, Cpu, Lock, Loader2, ImagePlus, MessageSquarePlus, Palette, Lightbulb
} from 'lucide-react';
import { GeneratedResult } from '../types';
import { staticAngles, dynamicAngleSlots } from '../constants';
import { 
  analyzeImageAndSuggestDescription,
  optimizePrompt,
  generateImage,
  getDynamicAnglePrompts,
  getCreativeConcept,
  translatePromptToEnglish,
} from '../services/geminiService';


const AIProductStudio = () => {
  const [mainImage, setMainImage] = useState<string | null>(null);
  const [productName, setProductName] = useState('');
  const [lightingSuggestion, setLightingSuggestion] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedResults, setGeneratedResults] = useState<GeneratedResult[]>([]);
  const [copiedId, setCopiedId] = useState<number | null>(null);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [customPrompt, setCustomPrompt] = useState('');
  const [isGeneratingCustom, setIsGeneratingCustom] = useState(false);
  const [isThinkingConcept, setIsThinkingConcept] = useState(false);

  const [remixTarget, setRemixTarget] = useState<GeneratedResult | null>(null);
  const [remixPrompt, setRemixPrompt] = useState('');
  const [remixRefImage, setRemixRefImage] = useState<string | null>(null);
  const [isRemixing, setIsRemixing] = useState(false);

  const [regenerateTarget, setRegenerateTarget] = useState<GeneratedResult | null>(null);
  const [regenerateSuffix, setRegenerateSuffix] = useState('');
  const [regenerateSuffixCn, setRegenerateSuffixCn] = useState('');
  const [isTranslating, setIsTranslating] = useState(false);
  const translationTimeoutRef = useRef<number | null>(null);

  const [isDownloading, setIsDownloading] = useState(false);
  const [downloadProgress, setDownloadProgress] = useState(0);

  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isOptimizing, setIsOptimizing] = useState(false);

  useEffect(() => {
    if (translationTimeoutRef.current) {
      clearTimeout(translationTimeoutRef.current);
    }

    if (regenerateSuffixCn.trim()) {
      setIsTranslating(true);
      translationTimeoutRef.current = window.setTimeout(async () => {
        try {
          const englishPrompt = await translatePromptToEnglish(regenerateSuffixCn);
          setRegenerateSuffix(englishPrompt);
        } catch (error) {
          console.error("Translation failed:", error);
          // Optionally set an error state
        } finally {
          setIsTranslating(false);
        }
      }, 500); // 500ms debounce
    } else {
        setIsTranslating(false);
    }

    return () => {
      if (translationTimeoutRef.current) {
        clearTimeout(translationTimeoutRef.current);
      }
    };
  }, [regenerateSuffixCn]);

  const updateResult = (id: number, updates: Partial<GeneratedResult>) => {
      setGeneratedResults(prev => prev.map(item =>
        item.id === id ? { ...item, ...updates } : item
      ));
    };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setMainImage(reader.result as string);
        setGeneratedResults([]);
        setProductName('');
        setCustomPrompt('');
        setLightingSuggestion('');
      };
      reader.readAsDataURL(file);
    }
  };

  const handleRemixRefUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setRemixRefImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const removeImage = (e: React.MouseEvent) => {
    e.stopPropagation();
    setMainImage(null);
    setGeneratedResults([]);
    setProductName('');
    setLightingSuggestion('');
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  const analyzeImageWithGemini = async () => {
    if (!mainImage) return;
    setIsAnalyzing(true);
    setLightingSuggestion('');
    try {
      const result = await analyzeImageAndSuggestDescription(mainImage);
      if (result) {
        setProductName(result.description);
        setLightingSuggestion(result.lighting);
      }
    } catch (error) {
      console.error("Analysis Error:", error);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const optimizePromptWithGemini = async () => {
    if (!productName) return;
    setIsOptimizing(true);
    try {
      const result = await optimizePrompt(productName);
      if (result) setProductName(result);
    } catch (error) {
      console.error("Optimization Error:", error);
    } finally {
      setIsOptimizing(false);
    }
  };

  const handleDownloadAll = async () => {
    const completedImages = generatedResults.filter(r => r.status === 'completed' && r.imageUrl);
    if (completedImages.length === 0) return;

    setIsDownloading(true);
    setDownloadProgress(0);

    for (let i = 0; i < completedImages.length; i++) {
      const result = completedImages[i];
      const link = document.createElement('a');
      link.href = result.imageUrl!;
      const safeName = result.name ? result.name.replace(/[^\w\u4e00-\u9fa5\s]/g, '').replace(/\s+/g, '_') : 'image';
      link.download = `AI_Product_${safeName}_${result.id}.png`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      setDownloadProgress(i + 1);
      if (i < completedImages.length - 1) {
        await new Promise(resolve => setTimeout(resolve, 1000));
      }
    }

    setTimeout(() => {
      setIsDownloading(false);
      setDownloadProgress(0);
    }, 1000);
  };

  const processGenerationError = (e: unknown): string => {
    if (e instanceof Error) {
        const message = e.message.toLowerCase();
        if (message.includes('api key') || message.includes('permission denied') || message.includes('401') || message.includes('403')) {
            return '认证失败 (Auth)';
        }
    }
    return '生成失败';
  };

  const handleGenerate = async () => {
    if (!mainImage) return;
    setIsGenerating(true);

    const initialResults: GeneratedResult[] = [
      ...staticAngles.map(angle => {
        const fullPromptSuffix = lightingSuggestion ? `${lightingSuggestion}, ${angle.promptSuffix}` : angle.promptSuffix;
        return {
          ...angle,
          imageUrl: null,
          status: 'loading' as const,
          finalPrompt: `${productName} ${fullPromptSuffix}`,
          isDynamic: false,
          description_cn: angle.description_cn
        }
      }),
      ...dynamicAngleSlots.map(angle => ({
        ...angle,
        imageUrl: null,
        status: 'analyzing' as const,
        finalPrompt: 'AI 正在分析补充视角...',
        isDynamic: true,
        description_cn: 'AI 正在探索独特视角...'
      }))
    ];
    setGeneratedResults(initialResults);

    // Step 1: Generate all static images
    const staticPromises = staticAngles.map(async (angle) => {
      await new Promise(r => setTimeout(r, (angle.id - 1) * 800));
      const fullPromptSuffix = lightingSuggestion ? `${lightingSuggestion}, ${angle.promptSuffix}` : angle.promptSuffix;
      try {
        const url = await generateImage(productName, fullPromptSuffix, mainImage);
        updateResult(angle.id, { imageUrl: url, status: url ? 'completed' : 'error' });
      } catch (e: unknown) {
        updateResult(angle.id, { status: 'error', errorMessage: processGenerationError(e) });
      }
    });

    await Promise.all(staticPromises);

    // Step 2: Analyze the generated angles and get dynamic prompts
    let dynamicPrompts: string[] = [];
    try {
        const existingAngleTypes = staticAngles.map(angle => angle.type);
        dynamicPrompts = await getDynamicAnglePrompts(mainImage, existingAngleTypes);
    } catch(e) {
        console.error("Dynamic prompt analysis failed", e);
        dynamicPrompts = [ "Top down flat lay view...", "Contextual in-hand shot..." ];
    }

    // Step 3: Generate dynamic images based on the new prompts
    const dynamicPromises = dynamicAngleSlots.map(async (slot, index) => {
      const specificPrompt = dynamicPrompts[index];
      const fullPromptSuffix = lightingSuggestion ? `${lightingSuggestion}, ${specificPrompt}` : specificPrompt;
      updateResult(slot.id, {
        name: `AI 智能补全 ${['A', 'B'][index]}`,
        type: 'Smart Complement',
        finalPrompt: `${productName} ${fullPromptSuffix}`,
        status: 'loading',
        description_cn: `AI 智能分析的独特构图 #${['A', 'B'][index]}`
      });
      await new Promise(r => setTimeout(r, (index * 1500)));
      try {
        const url = await generateImage(productName, fullPromptSuffix, mainImage);
        updateResult(slot.id, { imageUrl: url, status: url ? 'completed' : 'error' });
      } catch (e: unknown) {
        updateResult(slot.id, { status: 'error', errorMessage: processGenerationError(e) });
      }
    });

    await Promise.all(dynamicPromises);
    setIsGenerating(false);
  };

  const handleCustomGenerate = async () => {
    if (!mainImage) return;
    setIsGeneratingCustom(true);

    let finalSuffix = customPrompt;
    let displayTitle = `自定义: ${customPrompt}`;

    if (!customPrompt.trim()) {
      setIsThinkingConcept(true);
      displayTitle = "大师级自动构思";
      try {
        finalSuffix = await getCreativeConcept(productName);
      } catch (e) {
        finalSuffix = `Cinematic commercial photography, in a minimalist studio with geometric shadows, 8k resolution, masterpiece`;
        console.error("Creative concept failed", e);
      } finally {
        setIsThinkingConcept(false);
      }
    }

    const fullFinalSuffix = lightingSuggestion ? `${lightingSuggestion}, ${finalSuffix}` : finalSuffix;

    const newId = Date.now();
    const newResult: GeneratedResult = {
      id: newId,
      name: displayTitle,
      type: 'Custom Masterpiece',
      status: 'loading',
      finalPrompt: `${productName} ${fullFinalSuffix}`,
      imageUrl: null,
      isDynamic: true,
      description_cn: customPrompt.trim() ? customPrompt : '大师级 AI 智能构思的独特商业场景'
    };
    setGeneratedResults(prev => [newResult, ...prev]);

    try {
      const url = await generateImage(productName, fullFinalSuffix, mainImage);
      updateResult(newId, { imageUrl: url, status: url ? 'completed' : 'error' });
    } catch (e) {
      updateResult(newId, { status: 'error', errorMessage: processGenerationError(e) });
    }
    setIsGeneratingCustom(false);
  };

  const handleRemixGenerate = async () => {
    if (!remixTarget || !remixTarget.imageUrl || !remixPrompt) return;
    setIsRemixing(true);

    const fullRemixPrompt = lightingSuggestion ? `${lightingSuggestion}, ${remixPrompt}` : remixPrompt;

    const newId = Date.now();
    const newResult: GeneratedResult = {
      id: newId,
      name: `Remix: ${remixTarget.name}`,
      type: 'Secondary Creation',
      status: 'loading',
      finalPrompt: `Remix of ${remixTarget.name}: ${fullRemixPrompt}`,
      imageUrl: null,
      isDynamic: true,
      description_cn: `二次创作: ${remixPrompt}`
    };
    setGeneratedResults(prev => [newResult, ...prev]);
    const originalImageUrl = remixTarget.imageUrl;
    setRemixTarget(null);

    try {
      const url = await generateImage(productName, fullRemixPrompt, originalImageUrl, remixRefImage);
      updateResult(newId, { imageUrl: url, status: url ? 'completed' : 'error' });
    } catch (e) {
      updateResult(newId, { status: 'error', errorMessage: processGenerationError(e) });
    }
    setIsRemixing(false);
    setRemixRefImage(null);
    setRemixPrompt('');
  };

  const openRemixModal = (result: GeneratedResult) => {
    setRemixTarget(result);
    setRemixPrompt('');
    setRemixRefImage(null);
  };

  const openRegenerateModal = (result: GeneratedResult) => {
    setRegenerateTarget(result);
    const suffix = result.finalPrompt.replace(productName, '').trim();
    setRegenerateSuffix(suffix);
    setRegenerateSuffixCn('');
  };

  const handleRegenerate = async () => {
    if (!regenerateTarget || !mainImage) return;

    const targetId = regenerateTarget.id;
    const newFullPrompt = `${productName} ${regenerateSuffix}`;
    setRegenerateTarget(null);

    updateResult(targetId, { status: 'loading', finalPrompt: newFullPrompt, description_cn: '自定义调整后的场景' });

    try {
        const url = await generateImage(productName, regenerateSuffix, mainImage);
        updateResult(targetId, { imageUrl: url, status: url ? 'completed' : 'error' });
    } catch (e) {
        updateResult(targetId, { status: 'error', errorMessage: processGenerationError(e) });
    }
  }

  const copyPrompt = (text: string, id: number) => {
    navigator.clipboard.writeText(text);
    setCopiedId(id);
    setTimeout(() => setCopiedId(null), 2000);
  };

  const isCustomGenerating = isGeneratingCustom || isThinkingConcept;

  return (
    <div className="font-sans selection:bg-indigo-100 text-slate-900">
      {previewImage && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/95 backdrop-blur-sm p-4 sm:p-8 animate-in fade-in duration-200" onClick={() => setPreviewImage(null)}>
          <div className="relative max-w-7xl w-full h-full flex items-center justify-center">
             <button onClick={() => setPreviewImage(null)} className="absolute top-4 right-4 text-white/70 hover:text-white bg-white/10 hover:bg-white/20 rounded-full p-2 z-50"><X className="w-8 h-8" /></button>
             <img src={previewImage} alt="Preview" className="max-w-full max-h-full object-contain rounded-lg shadow-2xl" onClick={(e) => e.stopPropagation()} />
          </div>
        </div>
      )}

      {regenerateTarget && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 animate-in fade-in zoom-in-95 duration-200">
            <div className="bg-white rounded-2xl shadow-2xl max-w-2xl w-full overflow-hidden flex flex-col max-h-[90vh]">
                <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-gray-50">
                    <h3 className="text-lg font-bold flex items-center text-purple-700">
                        <RefreshCw className="w-5 h-5 mr-2" />
                        调整并重绘 (Adjust & Redraw)
                    </h3>
                    <button onClick={() => setRegenerateTarget(null)} className="p-1 hover:bg-gray-200 rounded-full transition-colors"><X className="w-5 h-5" /></button>
                </div>

                <div className="p-6 overflow-y-auto space-y-4">
                    <div className="flex gap-6">
                        <img src={regenerateTarget.imageUrl || ''} alt="Source" className="w-1/3 h-40 object-cover rounded-lg shadow-sm border border-gray-200 flex-shrink-0" />
                        <div className="w-2/3">
                           <label className="block text-sm font-bold text-gray-800 mb-1">商品核心描述 (固定)</label>
                           <p className="text-sm p-2 bg-gray-100 border border-gray-200 rounded-md text-gray-600">{productName}</p>
                        </div>
                    </div>
                    <div>
                        <label className="block text-sm font-bold text-gray-800 mb-1">用中文描述你的场景 (AI 实时翻译)</label>
                        <textarea 
                            className="w-full border border-gray-300 rounded-lg p-3 text-sm focus:ring-2 focus:ring-purple-500 outline-none resize-none h-20"
                            placeholder="例如：在赛博朋克风格的雨夜街道上"
                            value={regenerateSuffixCn}
                            onChange={(e) => setRegenerateSuffixCn(e.target.value)}
                        />
                    </div>
                     <div>
                        <label className="block text-sm font-bold text-gray-800 mb-1 flex items-center">
                            AI 翻译结果 (可编辑)
                            {isTranslating && <Loader2 className="w-4 h-4 ml-2 animate-spin text-purple-500" />}
                        </label>
                        <textarea 
                            className="w-full border border-gray-300 rounded-lg p-3 text-sm focus:ring-2 focus:ring-purple-500 outline-none resize-none h-24 bg-gray-50"
                            value={regenerateSuffix}
                            onChange={(e) => setRegenerateSuffix(e.target.value)}
                        />
                    </div>
                </div>

                <div className="p-4 border-t border-gray-100 bg-gray-50 flex justify-end gap-3">
                    <button onClick={() => setRegenerateTarget(null)} className="px-4 py-2 text-gray-600 hover:bg-gray-200 rounded-lg font-medium text-sm transition-colors">取消</button>
                    <button 
                        onClick={handleRegenerate}
                        className="px-6 py-2 bg-purple-600 text-white rounded-lg font-bold text-sm hover:bg-purple-700 shadow-lg shadow-purple-200 flex items-center"
                    >
                        <RefreshCw className="w-4 h-4 mr-2" />
                        重新绘制
                    </button>
                </div>
            </div>
        </div>
      )}

      {remixTarget && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 animate-in fade-in zoom-in-95 duration-200">
            <div className="bg-white rounded-2xl shadow-2xl max-w-2xl w-full overflow-hidden flex flex-col max-h-[90vh]">
                <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-gray-50">
                    <h3 className="text-lg font-bold flex items-center text-indigo-700">
                        <Palette className="w-5 h-5 mr-2" />
                        二次创作 (Remix Studio)
                    </h3>
                    <button onClick={() => setRemixTarget(null)} className="p-1 hover:bg-gray-200 rounded-full transition-colors"><X className="w-5 h-5" /></button>
                </div>

                <div className="p-6 overflow-y-auto">
                    <div className="flex gap-6 mb-6">
                        <div className="w-1/3 flex-shrink-0">
                            <label className="block text-xs font-bold text-gray-500 uppercase mb-2">当前底图</label>
                            <img src={remixTarget.imageUrl || ''} alt="Source" className="w-full h-32 object-cover rounded-lg shadow-sm border border-gray-200" />
                        </div>
                        <div className="w-2/3 space-y-4">
                            <div>
                                <label className="block text-sm font-bold text-gray-800 mb-1">你想如何修改这张图？</label>
                                <textarea 
                                    className="w-full border border-gray-300 rounded-lg p-3 text-sm focus:ring-2 focus:ring-indigo-500 outline-none resize-none h-24"
                                    placeholder="例如：把背景改成夜晚的赛博朋克街道，或者增加雨水效果..."
                                    value={remixPrompt}
                                    onChange={(e) => setRemixPrompt(e.target.value)}
                                />
                            </div>
                        </div>
                    </div>

                    <div className="bg-indigo-50 rounded-xl p-4 border border-indigo-100 mb-6">
                        <label className="block text-sm font-bold text-indigo-900 mb-2 flex items-center">
                            <ImagePlus className="w-4 h-4 mr-2" />
                            (可选) 参考风格图
                        </label>
                        <p className="text-xs text-indigo-700 mb-3">上传一张你喜欢的风格/构图图片，AI 将尝试模仿其风格。</p>
                        <div className="flex items-center gap-4">
                            <div className="relative">
                                <input type="file" onChange={handleRemixRefUpload} className="hidden" id="remix-upload" accept="image/*" />
                                <label htmlFor="remix-upload" className="px-4 py-2 bg-white border border-indigo-200 rounded-lg text-sm text-indigo-700 font-medium cursor-pointer hover:bg-indigo-50 transition-colors flex items-center">
                                    <Upload className="w-4 h-4 mr-2" />
                                    上传参考图
                                </label>
                            </div>
                            {remixRefImage && (
                                <div className="relative w-12 h-12">
                                    <img src={remixRefImage} alt="Remix Reference" className="w-12 h-12 object-cover rounded-md border border-gray-300" />
                                    <button onClick={() => setRemixRefImage(null)} className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-0.5"><X className="w-3 h-3" /></button>
                                </div>
                            )}
                        </div>
                    </div>
                </div>

                <div className="p-4 border-t border-gray-100 bg-gray-50 flex justify-end gap-3">
                    <button onClick={() => setRemixTarget(null)} className="px-4 py-2 text-gray-600 hover:bg-gray-200 rounded-lg font-medium text-sm transition-colors">取消</button>
                    <button 
                        onClick={handleRemixGenerate}
                        disabled={!remixPrompt || isRemixing}
                        className="px-6 py-2 bg-indigo-600 text-white rounded-lg font-bold text-sm hover:bg-indigo-700 shadow-lg shadow-indigo-200 disabled:opacity-50 disabled:cursor-not-allowed flex items-center"
                    >
                        {isRemixing ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <Wand2 className="w-4 h-4 mr-2" />}
                        {isRemixing ? '生成中...' : '生成新创意'}
                    </button>
                </div>
            </div>
        </div>
      )}

      <header className="bg-white border-b border-gray-200 sticky top-0 z-20 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className="bg-gradient-to-br from-pink-600 to-purple-700 p-2 rounded-lg shadow-lg shadow-pink-200">
              <Camera className="w-5 h-5 text-white" />
            </div>
            <span className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-pink-600 to-purple-600">
              AI RealShot <span className="text-xs font-normal text-gray-400 ml-1">Pro Gen</span>
            </span>
          </div>
          <div className="flex items-center space-x-3">
             <div className="flex items-center px-2 py-1 bg-green-50 text-green-700 rounded-lg border border-green-100 text-xs font-medium">
                <Cpu className="w-3 h-3 mr-1" />
                Gemini (Auto-Select)
             </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="mb-8 bg-gradient-to-r from-purple-50 to-pink-50 border border-purple-100 rounded-xl p-4 flex items-start gap-3 shadow-sm">
          <Sparkles className="w-5 h-5 text-purple-600 flex-shrink-0 mt-0.5" />
          <div className="text-sm text-purple-900">
            <p className="font-bold mb-1">AI 摄影师就绪 (Pro Mode)</p>
            <p className="leading-relaxed opacity-90">
              全自动对接环境最强模型，支持 8K 画质生成。所有图片均支持 <strong>二次创作 (Remix)</strong>。
            </p>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
          <div className="lg:col-span-4 space-y-6">
            <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
              <div className="flex justify-between items-center mb-4">
                <h2 className="text-lg font-bold flex items-center">
                  <ImageIcon className="w-5 h-5 mr-2 text-indigo-600" />
                  原图上传
                </h2>
              </div>
              <div className={`relative border-2 border-dashed rounded-xl p-8 text-center transition-all duration-300 overflow-hidden ${mainImage ? 'border-indigo-200 bg-gray-50' : 'border-gray-300 hover:border-indigo-400 hover:bg-gray-50'}`}>
                <input type="file" ref={fileInputRef} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10" onChange={handleImageUpload} accept="image/*" />
                {mainImage ? (
                  <div className="relative group">
                    <img src={mainImage} alt="Uploaded" className="w-full h-64 object-contain rounded-lg shadow-sm mx-auto" />
                    <button onClick={removeImage} className="absolute top-2 right-2 p-2 bg-white rounded-full text-red-500 shadow-md hover:bg-red-50 z-20 pointer-events-auto transition-transform hover:scale-110"><Trash2 className="w-4 h-4" /></button>
                    <div className="absolute inset-0 bg-black/50 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity rounded-lg z-10 pointer-events-none"><p className="text-white font-medium flex items-center"><RefreshCw className="w-4 h-4 mr-2" />更换图片</p></div>
                  </div>
                ) : (
                  <div className="space-y-4 py-8 pointer-events-none">
                    <div className="w-16 h-16 bg-indigo-50 text-indigo-600 rounded-full flex items-center justify-center mx-auto shadow-sm"><Upload className="w-8 h-8" /></div>
                    <div><p className="text-gray-900 font-medium">点击上传商品图</p><p className="text-gray-500 text-xs mt-1">支持 JPG, PNG</p></div>
                  </div>
                )}
              </div>
              {mainImage && (
                <button onClick={analyzeImageWithGemini} disabled={isAnalyzing} className="w-full mt-3 py-2 px-3 bg-indigo-50 hover:bg-indigo-100 text-indigo-700 rounded-lg text-xs font-semibold transition-colors flex items-center justify-center border border-indigo-200">
                   {isAnalyzing ? <Loader2 className="w-3 h-3 mr-2 animate-spin" /> : <Eye className="w-3 h-3 mr-2" />}
                   {isAnalyzing ? "正在分析..." : "第一步：AI 识别商品特征"}
                </button>
              )}
              <div className="mt-4">
                 <div className="flex justify-between items-center mb-1.5">
                    <label className="text-xs font-bold text-gray-500 uppercase tracking-wider">辅助描述</label>
                    <button onClick={optimizePromptWithGemini} disabled={!productName || isOptimizing} className="text-[10px] text-purple-600 hover:text-purple-700 font-bold flex items-center bg-purple-50 px-2 py-1 rounded-md transition-colors disabled:opacity-50">
                      {isOptimizing ? <Loader2 className="w-3 h-3 animate-spin mr-1" /> : <Wand2 className="w-3 h-3 mr-1" />}
                      {isOptimizing ? "优化" : "AI 润色"}
                    </button>
                  </div>
                  <p className="text-xs text-gray-500 mb-2">
                    AI 自动识别的核心英文描述，用于生成图片。可手动修改或点击“AI 润色”优化。
                  </p>
                  <textarea rows={2} value={productName} onChange={(e) => setProductName(e.target.value)} placeholder="例如：Nike Air Max 红色运动鞋..." className="w-full px-4 py-2.5 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all text-sm resize-none" />
              </div>
              {lightingSuggestion && (
                  <div className="mt-4 p-3 bg-indigo-50 border border-indigo-200 rounded-lg">
                      <div className="flex items-start">
                          <Lightbulb className="w-4 h-4 mr-2 text-indigo-600 flex-shrink-0 mt-0.5" />
                          <div>
                              <h4 className="text-xs font-bold text-indigo-800">
                                  AI 光照建议
                              </h4>
                              <p className="text-sm text-indigo-900 leading-relaxed mt-1">{lightingSuggestion}</p>
                          </div>
                      </div>
                  </div>
              )}
            </div>

            <div className="bg-gradient-to-br from-indigo-600 to-purple-700 rounded-2xl shadow-lg shadow-indigo-200 text-white p-6 relative overflow-hidden">
                <div className="absolute top-0 right-0 -mr-8 -mt-8 w-32 h-32 bg-white opacity-10 rounded-full blur-2xl pointer-events-none"></div>
                <h3 className="text-lg font-bold flex items-center mb-3 relative z-10"><Palette className="w-5 h-5 mr-2" />自定义创意 / 大师模式</h3>
                <p className="text-indigo-100 text-xs mb-4 relative z-10">输入想法，或<span className="font-bold text-white underline decoration-indigo-300 decoration-wavy mx-1">留空</span>点击生成，AI 将智能构思贴合产品的场景。</p>
                <div className="relative z-10 space-y-3">
                    <input type="text" value={customPrompt} onChange={(e) => setCustomPrompt(e.target.value)} placeholder="留空，由 AI 智能构思独特场景..." className="w-full px-4 py-2.5 bg-white/10 border border-indigo-400/30 rounded-lg text-white placeholder-indigo-200/70 focus:bg-white/20 focus:outline-none focus:ring-2 focus:ring-white/30 text-sm backdrop-blur-sm" />
                    <button onClick={handleCustomGenerate} disabled={!mainImage || isCustomGenerating} className="w-full py-2.5 bg-white text-indigo-600 rounded-lg font-bold text-sm shadow hover:bg-indigo-50 transition-colors flex items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed group">
                        {isCustomGenerating ? <><Loader2 className="w-4 h-4 mr-2 animate-spin" /> {isThinkingConcept ? 'AI 正在构思...' : '生成中...'}</> : (customPrompt.trim() ? <><MessageSquarePlus className="w-4 h-4 mr-2" />生成创意脚本 & 图片</> : <><Shuffle className="w-4 h-4 mr-2 group-hover:rotate-180 transition-transform" />大师级智能构思</>)}
                    </button>
                </div>
            </div>

            <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
                <h3 className="text-sm font-bold text-gray-700 mb-3 flex items-center"><Layers className="w-4 h-4 mr-2" />批量智能视图 (9经典 + 2智能)</h3>
                <button onClick={handleGenerate} disabled={!mainImage || isGenerating} className={`w-full py-3 px-4 rounded-xl font-bold text-white shadow-lg shadow-gray-200 transition-all transform active:scale-[0.98] ${!mainImage || isGenerating ? 'bg-gray-300 cursor-not-allowed shadow-none' : 'bg-gray-800 hover:bg-gray-900'} flex items-center justify-center text-sm`}>
                  {isGenerating ? <><Loader2 className="w-4 h-4 mr-2 animate-spin" />正在智能绘制 (11张)...</> : <><Sparkles className="w-4 h-4 mr-2" />生成标准+智能创意图</>}
                </button>
            </div>
          </div>

          <div className="lg:col-span-8">
            <div className="flex items-center justify-between mb-6">
              <h2 className="text-xl font-bold text-gray-800 flex items-center"><Layers className="w-6 h-6 mr-2 text-pink-600" />生成结果 (Real Output)</h2>
              {generatedResults.some(r => r.status === 'completed') && (
                <button onClick={handleDownloadAll} disabled={isDownloading} className={`flex items-center px-4 py-2 border rounded-lg text-sm font-medium transition-colors shadow-sm ${isDownloading ? 'bg-indigo-50 border-indigo-200 text-indigo-700 cursor-wait' : 'bg-white border-gray-200 text-gray-600 hover:bg-gray-50'}`}>
                  {isDownloading ? (
                    <><Loader2 className="w-4 h-4 mr-2 animate-spin" />正在保存 ({downloadProgress}/{generatedResults.filter(r => r.status === 'completed').length})...</>
                  ) : (
                    <><Download className="w-4 h-4 mr-2" />全部保存</>
                  )}
                </button>
              )}
            </div>

            {generatedResults.length === 0 && (
              <div className="bg-white border-2 border-dashed border-gray-200 rounded-2xl h-[500px] flex flex-col items-center justify-center text-center p-8">
                <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mb-4 animate-pulse"><ImagePlus className="w-10 h-10 text-gray-300" /></div>
                <h3 className="text-lg font-medium text-gray-900">等待生成任务</h3>
                <p className="text-gray-500 mt-2 max-w-sm text-sm">您可以选择批量生成 10 种视图（包含 AI 智能分析出的独特视角），或者使用自定义模块生成创意场景。</p>
              </div>
            )}

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {generatedResults.map((result) => (
                <div key={result.id} className={`bg-white rounded-xl border shadow-sm hover:shadow-md transition-all duration-300 overflow-hidden group flex flex-col ${result.isDynamic || result.type.includes('Custom') ? 'border-indigo-200 ring-2 ring-indigo-50' : 'border-gray-100'} ${result.status === 'error' ? 'border-red-100 bg-red-50' : ''}`}>
                  <div className="relative h-48 bg-gray-100 overflow-hidden flex items-center justify-center bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]">
                    {(result.status === 'loading' || result.status === 'analyzing') && (
                      <div className="flex flex-col items-center justify-center text-gray-400 space-y-2 px-4 text-center">
                        {result.status === 'analyzing' ? <BrainCircuit className="w-8 h-8 animate-pulse text-indigo-500" /> : <Loader2 className="w-8 h-8 animate-spin text-purple-600" />}
                        <span className="text-xs font-medium">{result.status === 'analyzing' ? 'AI 正在探索独特视角...' : 'AI 绘制中...'}</span>
                      </div>
                    )}
                    {result.status === 'error' && (
                      <div className="flex flex-col items-center justify-center text-red-400 space-y-2 px-4 text-center">
                        {result.errorMessage?.includes('Auth') ? <Lock className="w-8 h-8" /> : <AlertCircle className="w-8 h-8" />}
                        <span className="text-xs font-medium">{result.errorMessage || '生成失败'}</span>
                      </div>
                    )}
                    {result.status === 'completed' && result.imageUrl && (
                      <img src={result.imageUrl} alt={result.name} className="w-full h-full object-cover transition-transform duration-700 hover:scale-105 cursor-pointer" onClick={() => setPreviewImage(result.imageUrl)} />
                    )}
                    <div className="absolute top-2 left-2 z-10"><span className={`backdrop-blur-md text-white text-[10px] px-2 py-0.5 rounded font-medium shadow-sm ${result.isDynamic || result.type.includes('Custom') ? 'bg-indigo-600/80' : 'bg-black/60'}`}>{result.type}</span></div>

                    {result.status === 'completed' && (
                      <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center space-x-2 backdrop-blur-[1px] pointer-events-none">
                        <button onClick={() => openRegenerateModal(result)} className="p-2 bg-purple-600 text-white rounded-full hover:bg-purple-700 shadow-lg transform hover:scale-110 transition-all pointer-events-auto" title="调整并重绘"><RefreshCw className="w-4 h-4" /></button>
                        <button onClick={() => openRemixModal(result)} className="p-2 bg-indigo-600 text-white rounded-full hover:bg-indigo-700 shadow-lg transform hover:scale-110 transition-all pointer-events-auto" title="二次创作/改图"><Edit className="w-4 h-4" /></button>
                        <button onClick={() => setPreviewImage(result.imageUrl)} className="p-2 bg-white rounded-full text-gray-800 hover:bg-gray-100 shadow-lg transform hover:scale-110 transition-transform pointer-events-auto" title="放大"><Maximize2 className="w-5 h-5" /></button>
                        <a href={result.imageUrl || '#'} download={`ai-product-${result.id}.png`} className="p-2 bg-white rounded-full text-gray-800 hover:bg-gray-100 shadow-lg transform hover:scale-110 transition-transform pointer-events-auto"><Download className="w-5 h-5" /></a>
                      </div>
                    )}
                  </div>

                  <div className="p-4 flex-1 flex flex-col justify-between">
                    <div>
                      <div className="flex justify-between items-start mb-1">
                          <h4 className="font-semibold text-gray-900 text-sm truncate pr-2" title={result.name}>{result.name}</h4>
                          {result.status === 'completed' && <span className="text-[10px] text-green-600 bg-green-50 px-1.5 py-0.5 rounded border border-green-100 font-medium flex items-center flex-shrink-0"><Check className="w-3 h-3 mr-1" /> OK</span>}
                      </div>
                      {result.description_cn && <p className="text-xs text-gray-600 mb-2 leading-relaxed">{result.description_cn}</p>}
                    </div>
                    <div className="mt-auto relative group/prompt pt-2 border-t border-gray-100">
                      <p className="text-[10px] text-gray-400 line-clamp-2 leading-relaxed cursor-help" title={result.finalPrompt}>
                          <span className="font-semibold">Prompt:</span> {result.finalPrompt}
                      </p>
                      <button onClick={() => copyPrompt(result.finalPrompt, result.id)} className="absolute right-0 top-1.5 p-1 bg-white border border-gray-200 rounded text-gray-400 hover:text-indigo-600 opacity-0 group-hover/prompt:opacity-100 transition-opacity">{copiedId === result.id ? <Check className="w-3 h-3 text-green-500" /> : <Copy className="w-3 h-3" />}</button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

