        Generate 2 PROFESSIONAL, HIGH-CONVERTING E-COMMERCE photography angle descriptions.

        CONTEXT: The following angles have ALREADY been generated: ${existingAngles.join(', ')}.
        GOAL: Provide 2 angles that are MISSING from the generated list to complete a perfect set. Avoid suggesting angles similar to the existing ones.

        Return ONLY the 2 descriptions separated by "|||". English only.`;

    const response = await ai.models.generateContent({
        model: config.textModel,
        contents: {
            parts: [{ text: analysisPrompt }, { inlineData: { mimeType, data } }]
        }
    });

    const analysisResult = response.text;

    const fallbacks = [
        "Top down flat lay view, perfectly vertical, organized composition, clean background, 8k",
        "Contextual in-hand shot to show scale and grip, realistic lighting, 8k"
    ];

    if (!analysisResult) {
        return fallbacks;
    }

    let dynamicPrompts = analysisResult.split('|||').map(s => s.trim());
    if (dynamicPrompts.length < 2) {
        return fallbacks;
    }

    for (let i = 0; i < 2; i++) {
        if (!dynamicPrompts[i] || dynamicPrompts[i].length < 10) {
            dynamicPrompts[i] = fallbacks[i];
        }
    }

    return dynamicPrompts.slice(0, 2);
}

