                        <a href={result.imageUrl || '#'} download={`ai-product-${result.id}.png`} className="p-2 bg-slate-700 rounded-full text-white hover:bg-slate-600 shadow-lg transform hover:scale-110 transition-transform pointer-events-auto border border-white/10"><Download className="w-5 h-5" /></a>
