```typescript
// Helper function inside component or outside
const convertAndDownload = async (dataUrl: string, filename: string, format: 'png' | 'jpg') => {
    let finalUrl = dataUrl;
    let finalFilename = filename;

    if (format === 'jpg' && dataUrl.startsWith('data:image/png')) {
        // Convert
        finalUrl = await new Promise<string>((resolve) => {
            const img = new Image();
            img.onload = () => {
                const canvas = document.createElement('canvas');
                canvas.width = img.width;
                canvas.height = img.height;
                const ctx = canvas.getContext('2d');
                if(ctx) {
                    ctx.fillStyle = '#FFFFFF'; // JPG doesn't support transparency
                    ctx.fillRect(0, 0, canvas.width, canvas.height); // Fill background
                    ctx.drawImage(img, 0, 0);
                    resolve(canvas.toDataURL('image/jpeg', 0.9)); // Adjust quality as needed
                } else {
                    console.error("Could not get 2d context");
                    resolve(dataUrl); // Return original if error
                }
            };
            img.onerror = () => {
                console.error("Image failed to load");
                resolve(dataUrl);
            };
            img.src = dataUrl;
        });
    }

    const a = document.createElement('a');
    a.href = finalUrl;
    a.download = finalFilename.endsWith('.jpg') || finalFilename.endsWith('.png') ? finalFilename : `${finalFilename}.${format}`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
};
```


