// Helper function for retrying operations with exponential backoff
async function retryWithBackoff<T>(fn: () => Promise<T>, retries = 2, delay = 1000): Promise<T> {
    try {
        return await fn();
    } catch (error: any) {
        if (retries === 0) throw error;

        // Retry on 503 (Unavailable/Deadline Exceeded) or 429 (Rate Limit)
        const isTransient = error.status === 503 || 
                            error.status === 429 || 
                            error.code === 503 ||
                            error.code === 429 ||
                            (error.message && (error.message.includes('Deadline') || error.message.includes('overloaded')));

        if (isTransient) {
            await new Promise(resolve => setTimeout(resolve, delay));
            return retryWithBackoff(fn, retries - 1, delay * 2);
        }

        throw error;
    }
}

