  const downloadImageHelper = async (dataUrl: string, filenameBase: string, format: 'png' | 'jpg') => {
      let finalUrl = dataUrl;
      let finalFilename = filenameBase;

      if (format === 'jpg') {
          // If already PNG (which is likely from data URL), convert to JPG
          if (dataUrl.startsWith('data:image')) {
               try {
                  finalUrl = await new Promise<string>((resolve, reject) => {
                      const img = new Image();
                      img.onload = () => {
                          const canvas = document.createElement('canvas');
                          canvas.width = img.width;
                          canvas.height = img.height;
                          const ctx = canvas.getContext('2d');
                          if(ctx) {
                              // Fill white background for JPG transparency issues
                              ctx.fillStyle = '#FFFFFF';
                              ctx.fillRect(0, 0, canvas.width, canvas.height);
                              ctx.drawImage(img, 0, 0);
                              resolve(canvas.toDataURL('image/jpeg', 0.92));
                          } else {
                              resolve(dataUrl); // Fallback
                          }
                      };
                      img.onerror = (e) => reject(e);
                      img.src = dataUrl;
                  });
               } catch (e) {
                  console.error("Conversion failed, falling back to original", e);
               }
          }
          finalFilename += '.jpg';
      } else {
          finalFilename += '.png';
      }

      const link = document.createElement('a');
      link.href = finalUrl;
      link.download = finalFilename;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
  };

  const handleDownloadAll = async () => {
    const completedImages = generatedResults.filter(r => r.status === 'completed' && r.imageUrl);
